import { useState, useEffect } from "react"

export function MyComponent() {
  const [micStream, setMicStream] = useState<MediaStream>()

  const startMic = async () => {
    const stream = await navigator.mediaDevices.getUserMedia({
      audio: true
    })
    setMicStream(stream)
  }

  useEffect(() => {
    return () => {
      micStream?.getTracks().forEach(track => track.stop())
    }
  }, [micStream])

  return (
    <>
      <button onClick={startMic}>Enable Microphone</button>
      <AudioVisualizer
        track={micStream}
        gradientColors={["#3b82f6", "#60a5fa", "#93c5fd"]}
      />
    </>
  )
}

// Works with standard MediaStream objects`}],micButton:`import { MicButton } from "agora-agent-uikit"
